import{_ as h,o as t,c as i,ag as a}from"./chunks/framework.CxZWPeXl.js";const d=JSON.parse('{"title":"Thực hành","description":"","frontmatter":{},"headers":[],"relativePath":"practice.md","filePath":"practice.md"}'),c={name:"practice.md"};function o(u,n,r,l,g,e){return t(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="thuc-hanh" tabindex="-1">Thực hành <a class="header-anchor" href="#thuc-hanh" aria-label="Permalink to &quot;Thực hành&quot;">​</a></h1><blockquote><p>Luyện tập kỹ năng giao tiếp bán hàng qua các đoạn hội thoại mô phỏng với AI.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Thực hành (Practice) là tính năng cốt lõi của AI Coach. Bạn sẽ tương tác với một khách hàng ảo do AI điều khiển. Khách hàng này sẽ phản ứng chân thực dựa trên các thuộc tính được cài đặt (tuổi, nghề nghiệp, thu nhập, tính cách), xây dựng môi trường an toàn để bạn rèn luyện xử lý tình huống.</p><h2 id="cach-bat-đau" tabindex="-1">Cách Bắt đầu <a class="header-anchor" href="#cach-bat-đau" aria-label="Permalink to &quot;Cách Bắt đầu&quot;">​</a></h2><ul><li>Nút <strong>&quot;Bắt đầu Trò chuyện&quot;</strong> trên Bảng điều khiển.</li><li>Nút <strong>&quot;Làm lại&quot;</strong> hoặc <strong>&quot;Tiếp tục&quot;</strong> trong Lịch sử.</li></ul><hr><h2 id="chon-kich-ban" tabindex="-1">Chọn Kịch bản <a class="header-anchor" href="#chon-kich-ban" aria-label="Permalink to &quot;Chọn Kịch bản&quot;">​</a></h2><p>Trong quá trình khởi tạo cuộc trò chuyện, bạn có thể lựa chọn các phương thức sau:</p><h3 id="kich-ban-ngau-nhien" tabindex="-1">Kịch bản Ngẫu nhiên <a class="header-anchor" href="#kich-ban-ngau-nhien" aria-label="Permalink to &quot;Kịch bản Ngẫu nhiên&quot;">​</a></h3><ul><li>Hệ thống tự động chọn một thẻ khách hàng ngẫu nhiên.</li><li>Dành cho luyện tập nhanh hoặc khi không có yêu cầu đặc thù.</li></ul><h3 id="kich-ban-tuy-chinh-cai-đat-nhan-vat" tabindex="-1">Kịch bản Tùy chỉnh (Cài đặt Nhân vật) <a class="header-anchor" href="#kich-ban-tuy-chinh-cai-đat-nhan-vat" aria-label="Permalink to &quot;Kịch bản Tùy chỉnh (Cài đặt Nhân vật)&quot;">​</a></h3><ul><li>Tự định nghĩa khách hàng theo nhu cầu (ví dụ: Khách thu nhập cao, đã kết hôn).</li><li>Bật công tắc <strong>&quot;Cài đặt Nhân vật&quot;</strong> để hiển thị Cửa sổ cài đặt Chân dung Khách hàng.</li></ul><h3 id="tai-len-kich-ban-tro-chuyen-moi" tabindex="-1">Tải lên Kịch bản Trò chuyện (Mới) <a class="header-anchor" href="#tai-len-kich-ban-tro-chuyen-moi" aria-label="Permalink to &quot;Tải lên Kịch bản Trò chuyện (Mới)&quot;">​</a></h3><ul><li>Bật công tắc <strong>&quot;Tải lên kịch bản trò chuyện&quot;</strong> để cung cấp bối cảnh cụ thể.</li><li>Cho phép bạn nhập hoặc tải lên một đoạn hội thoại mẫu, bối cảnh đặc thù để AI tuân theo một cách nghiêm ngặt trong suốt quá trình luyện tập.</li></ul><h3 id="thu-lai-tu-lich-su" tabindex="-1">Thử lại (Từ Lịch sử) <a class="header-anchor" href="#thu-lai-tu-lich-su" aria-label="Permalink to &quot;Thử lại (Từ Lịch sử)&quot;">​</a></h3><ul><li>Gặp lại khách hàng y hệt lần trước bằng nút Làm lại.</li><li>Thử nghiệm các chiến thuật khác nhau.</li></ul><h3 id="tiep-tuc-tu-lich-su" tabindex="-1">Tiếp tục (Từ Lịch sử) <a class="header-anchor" href="#tiep-tuc-tu-lich-su" aria-label="Permalink to &quot;Tiếp tục (Từ Lịch sử)&quot;">​</a></h3><ul><li>Tiếp tục trò chuyện dang dở.</li><li>Khách hàng sẽ nhớ mang máng những gì đã trao đổi trong phiên trước.</li></ul><hr><h2 id="cai-đat-chan-dung-khach-hang" tabindex="-1">Cài đặt Chân dung Khách hàng <a class="header-anchor" href="#cai-đat-chan-dung-khach-hang" aria-label="Permalink to &quot;Cài đặt Chân dung Khách hàng&quot;">​</a></h2><p>Khi bật &quot;Cài đặt Nhân vật&quot;, bạn có thể tự điền các thông tin. Các trường để trống sẽ được AI tự hoàn thiện.</p><ul><li><strong>Cơ bản</strong>: Tuổi, Giới tính, Tính cách (MBTI 16 loại), Thu nhập, Nghề nghiệp.</li><li><strong>Tính cách MBTI</strong>: Ảnh hưởng mạnh đến cách ra quyết định và phản ứng của khách.</li><li><strong>Gia đình</strong>: Tình trạng hôn nhân, Số con, Tuổi &amp; Giới tính con cái.</li><li><strong>Mối quan hệ</strong>: Khách lạ hay người quen/người thân. Nếu là người quen, cần điền thêm &quot;Mô tả Mối quan hệ&quot;.</li></ul><hr><h2 id="giao-dien-tro-chuyen" tabindex="-1">Giao diện Trò chuyện <a class="header-anchor" href="#giao-dien-tro-chuyen" aria-label="Permalink to &quot;Giao diện Trò chuyện&quot;">​</a></h2><ul><li><strong>Trái</strong>: Thông tin chi tiết khách hàng và thanh tiến độ.</li><li><strong>Giữa</strong>: Khung hội thoại chính với lịch sử tin nhắn.</li><li><strong>Trên</strong>: Lời mở đầu tình huống, Đồng hồ đo thời gian phiên bản thực.</li><li><strong>Phải Trên</strong>: Nút &quot;Kết thúc trò chuyện&quot; màu đỏ.</li></ul><h3 id="quy-tac-an-toan" tabindex="-1">Quy tắc An toàn <a class="header-anchor" href="#quy-tac-an-toan" aria-label="Permalink to &quot;Quy tắc An toàn&quot;">​</a></h3><p>Trí tuệ nhân tạo được bảo vệ bằng cơ chế kiểm duyệt nội dung.</p><ul><li>Không gửi thông tin cá nhân thật (CCCD, SĐT...).</li><li>Không đăng nội dung phản cảm, vi phạm điều khoản chính sách. Nếu vi phạm, tin nhắn sẽ bị chặn ngay lập tức.</li></ul><hr><h2 id="cac-giai-đoan-ban-hang" tabindex="-1">Các Giai đoạn Bán hàng <a class="header-anchor" href="#cac-giai-đoan-ban-hang" aria-label="Permalink to &quot;Các Giai đoạn Bán hàng&quot;">​</a></h2><p>Được thiết kế theo định nghĩa của quản trị viên hệ thống (VD: Phá băng, Khám phá nhu cầu, Đưa ra giải pháp, Xử lý từ chối, Chốt sale).</p><ul><li>AI sẽ thực hiện đánh giá tổng thể tiến độ đạt được các giai đoạn <strong>SAU KHI</strong> cuộc gọi kết thúc, không phải trong thời gian thực. Hãy tập trung xây dựng mạch hội thoại mượt mà!</li></ul><hr><h2 id="ket-thuc-tro-chuyen" tabindex="-1">Kết thúc Trò chuyện <a class="header-anchor" href="#ket-thuc-tro-chuyen" aria-label="Permalink to &quot;Kết thúc Trò chuyện&quot;">​</a></h2><ul><li><strong>Chủ động</strong>: Nhấn &quot;Kết thúc trò chuyện&quot; &gt; Xác nhận.</li><li><strong>Khách hàng yêu cầu dừng</strong>: Khi AI cho biết khách hàng muốn kết thúc cuộc gọi (ví dụ: khách nói có việc bận), hệ thống sẽ bật lên lựa chọn &quot;Cố gắng tiếp tục&quot; (cố gắng níu kéo) hoặc &quot;Chấp nhận kết thúc&quot;.</li></ul><p>Sau đó, hệ thống sẽ tự động chuyển hướng và khởi tạo Báo cáo Đánh giá toàn diện.</p>',37)])])}const b=h(c,[["render",o]]);export{d as __pageData,b as default};
